@startuml
' Define color scheme
skinparam backgroundColor #FFFFFF
skinparam nodeBackgroundColor #F5F5F5
skinparam nodeBorderColor #333333
skinparam nodeTextColor #000000
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classTextColor #000000
skinparam actorBackgroundColor #E0F7FA
skinparam actorBorderColor #00838F
skinparam actorTextColor #000000
skinparam interfaceBackgroundColor #E1BEE7
skinparam interfaceBorderColor #8E24AA
skinparam interfaceTextColor #000000
skinparam databaseBackgroundColor #E8F5E9
skinparam databaseBorderColor #388E3C
skinparam databaseTextColor #000000

' Define classes
class "Personnage" {
  void combattre()
  void setArme(ComportementArme)
}

class "Aventure" {
  void main(String)
}

class "Troll" {
}

class "Roi" {
}

class "Reine" {
}

class "Chevalier" {
}

class "ComportementArme" {
  void utiliserArme()
}

class "ComportementPoignard" {
  void utiliserArme()
}

class "ComportementEpee" {
  void utiliserArme()
}

class "ComportementArc" {
  void utiliserArme()
}

' Define relationships
Personnage --|> Troll
Personnage --|> Roi
Personnage --|> Reine
Personnage --|> Chevalier
Personnage --> ComportementArme : 1
ComportementArme <|-- ComportementPoignard
ComportementArme <|-- ComportementEpee
ComportementArme <|-- ComportementArc

' Define actors
actor "A" as A
actor "C" as C
actor "I" as I

' Apply actors to classes
A -> Personnage
C -> Troll
C -> Roi
C -> Reine
C -> Chevalier
C -> ComportementPoignard
C -> ComportementEpee
C -> ComportementArc
I -> ComportementArme

@enduml
